function countMaxSubarray(arr) {
    let current = 0;
    let count = 0;
    const freq = [];

    for (let i = 0; i < arr.length; i++) {
        if (arr[i] !== current) {
            current = arr[i];
            freq.push(count);
            count = 0;
        }
        count++;
    }
    freq.push(count);

    let maximum = Number.MIN_SAFE_INTEGER;

    for (let i = 0; i < freq.length; i++) {
        let sum = 0;
        if (i % 2 !== 0) {
            sum = freq[i];
        } else {
            sum = freq[i];
            if (i > 0) sum += freq[i - 1];
            if (i < freq.length - 1) sum += freq[i + 1];
        }
        maximum = Math.max(maximum, sum);
    }

    // Handle the special case
    if (freq.length === 2 && freq[0] === 0) {
        return arr.length - 1;
    }

    return maximum;
}

